```

Для решения этой задачи на языке Go (который наиболее часто используется для подобных системных инструментов), нам потребуется реализовать паттерн «Строитель» (Builder) и создать кастомный `http.RoundTripper`. 

Кастомный `RoundTripper` необходим, чтобы автоматически добавлять заголовки и учетные данные аутентификации к каждому исходящему запросу.

Вот полная реализация:

```go
package main

import (
	"crypto/tls"
	"crypto/x509"
	"fmt"
	"net/http"
	"net/url"
	"time"
)

// AuthConfig хранит учетные данные для аутентификации клиента в Elasticsearch
type AuthConfig struct {
	Username string
	Password string
}

// ProxyConfig хранит настройки прокси-сервера
type ProxyConfig struct {
	URL      *url.URL
	Username string
	Password string
}

// Transport представляет интерфейс для выполнения запросов
type Transport interface {
	Do(req *http.Request) (*http.Response, error)
}

// elasticRoundTripper — это обертка над http.RoundTripper, 
// которая внедряет заголовки и аутентификацию в каждый запрос.
type elasticRoundTripper struct {
	base       http.RoundTripper
	headers    map[string]string
	authConfig *AuthConfig
}

func (r *elasticRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
	// 1. Добавляем пользовательские заголовки
	for key, value := range r.headers {
		req.Header.Set(key, value)
	}

	// 2. Добавляем аутентификацию клиента (Basic Auth)
	if r.authConfig != nil {
		req.SetBasicAuth(r.authConfig.Username, r.authConfig.Password)
	}

	return r.base.RoundTrip(req)
}

// TransportBuilder — структура для построения транспорта
type TransportBuilder struct {
	proxy          *ProxyConfig
	disableProxy   bool
	clientAuth     *AuthConfig
	tlsConfig      *tls.Config
	headers        map[string]string
	timeout        time.Duration
}

// NewTransportBuilder создает новый экземпляр билдера
func NewTransportBuilder() *TransportBuilder {
	return &TransportBuilder{
		headers: make(map[string]string),
	}
}

// SetProxy настраивает прокси с опциональным логином и паролем
func (b *TransportBuilder) SetProxy(proxyURL *url.URL, username, password string) *TransportBuilder {
	b.proxy = &ProxyConfig{
		URL:      proxyURL,
		Username: username,
		Password: password,
	}
	return b
}

// DisableProxy отключает использование прокси (включая системные)
func (b *TransportBuilder) DisableProxy() *TransportBuilder {
	b.disableProxy = true
	return b
}

// SetClientAuth устанавливает учетные данные для Elasticsearch
func (b *TransportBuilder) SetClientAuth(username, password string) *TransportBuilder {
	b.clientAuth = &AuthConfig{Username: username, Password: password}
	return b
}

// SetTLSConfig устанавливает конфигурацию TLS (для проверки сертификатов)
func (b *TransportBuilder) SetTLSConfig(tlsConfig *tls.Config) *TransportBuilder {
	b.tlsConfig = tlsConfig
	return b
}

// AddHeader добавляет заголовок ко всем запросам
func (b *TransportBuilder) AddHeader(key, value string) *TransportBuilder {
	b.headers[key] = value
	return b
}

// SetTimeout устанавливает глобальный тайм-аут
func (b *TransportBuilder) SetTimeout(timeout time.Duration) *TransportBuilder {
	b.timeout = timeout
	return b
}

// Build создает и возвращает Transport (в данном случае http.Client)
func (b *TransportBuilder) Build() (*http.Client, error) {
	// Создаем базовый http.Transport
	transport := &http.Transport{
		TLSClientConfig: b.tlsConfig,
	}

	// Настройка прокси
	if !b.disableProxy && b.proxy != nil {
		proxyURL := *b.proxy.URL
		// Если указаны логин/пароль для прокси, добавляем их в URL
		if b.proxy.Username != "" || b.proxy.Password != "" {
			proxyURL.User = url.UserPassword(b.proxy.Username, b.proxy.Password)
		}
		transport.Proxy = http.ProxyURL(proxyURL)
	} else {
		// Явно отключаем прокси (включая системные переменные окружения)
		transport.Proxy = nil
	}

	// Оборачиваем транспорт в наш elasticRoundTripper для обработки заголовков и Auth
	wrappedTransport := &elasticRoundTripper{
		base:       transport,
		headers:    b.headers,
		authConfig: b.clientAuth,
	}

	// Создаем клиент
	client := &http.Client{
		Transport: wrappedTransport,
		Timeout:   b.timeout,
	}

	return client, nil
}

func main() {
	// Пример использования:
	proxyURL, _ := url.Parse("http://proxy.example.com:8080")

	// Создаем корневой сертификат (имитация загрузки CA)
	// В реальном коде вы бы загрузили его из файла
	tlsConfig := &tls.Config{
		InsecureSkipVerify: false, // Включаем проверку
	}

	client, err := NewTransportBuilder().
		SetProxy(proxyURL, "proxy_user", "proxy_pass"). // Настройка прокси
		SetClientAuth("elastic_user", "secret_pass").  // Аутентификация в ES
		SetTLSConfig(tlsConfig).                       // Проверка сертификата
		AddHeader("Content-Type", "application/json"). // Общий заголовок
		AddHeader("X-Custom-Header", "ElasticClient").
		SetTimeout(30 * time.Second).                  // Тайм-аут
		Build()

	if err != nil {
		panic(err)
	}

	fmt.Printf("Client built successfully: %+v\n", client)
	_ = client
}
```

### Разбор реализации согласно требованиям:

1.  **Настройка прокси с аутентификацией**: В методе `SetProxy` мы сохраняем URL и учетные данные. В методе `Build` мы используем `url.UserPassword`, чтобы внедрить их непосредственно в URL прокси-сервера, что является стандартным способом для `http.ProxyURL`.
2.  **Отключение прокси**: Если вызван `DisableProxy()`, поле `transport.Proxy` устанавливается в `nil`. В Go это явно говорит стандартной библиотеке игнорировать системные переменные окружения (такие как `HTTP_PROXY`).
3.  **Учетные данные клиента**: Мы реализовали `elasticRoundTripper`. Это "прослойка", которая перехватывает каждый запрос перед отправкой и вызывает `req.SetBasicAuth(...)`. Это гарантирует, что вам не нужно добавлять логин/пароль вручную в каждом методе API.
4.  **Проверка сертификата**: Через `SetTLSConfig` пользователь может передать настроенный `*tls.Config`. Если передать туда `RootCAs` с вашим сертификатом, клиент будет доверять только вашему CA.
5.  **HTTP-заголовки**: Аналогично аутентификации, `elasticRoundTripper` проходит циклом по карте `headers` и применяет их к каждому запросу.
6.  **Глобальный тайм-аут**: Устанавливается напрямую в `http.Client.Timeout`, что ограничивает общее время выполнения запроса (включая соединение, чтение и запись).

### Почему выбран такой подход?
Использование `RoundTripper` — это самый чистый способ реализации "сквозной" логики (cross-cutting concerns) в Go. Это позволяет отделить логику построения соединения от логики бизнес-запросов к Elasticsearch.

